                    ctx.valid_drag = valid;
                    ctx.is_drop_target = true;
                }).with_named_effect("drop_activate", |_ctx, props, send| {
                    let platform = use_platform_effects();
                    let delay = Duration::from_millis(props.activate_delay_ms as u64);
