            // ── Drag leave ──────────────────────────────────────────────────
            // Adapter invokes `on_drop_exit` callback.
            (State::DragOver, Event::DragLeave) => {
                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
                    ctx.valid_drag = false;
                    ctx.is_drop_target = false;
                }).cancel_effect("drop_activate"))
