    #[cfg(feature = "std")]
    #[must_use]
    pub fn as_path(&self) -> Option<&Path> {
        match &self.inner {
            DirectoryHandleInner::Path(path) => Some(path.as_path()),
            DirectoryHandleInner::Opaque => None,
        }
    }
}

